                {/* Boutons Éditer et Supprimer toujours visibles */}
                <button title="Éditer" onClick={() => onEdit(s)} style={actionBtnStyle} onMouseOver={e => e.currentTarget.style.background = C.yellow} onMouseOut={e => e.currentTarget.style.background = C.arctic}><Edit size={15} /></button>
